class Solution:
    def isWinner(self, player1, player2):
        def score(frames):
            n = len(frames)
            multipliers = [1] * n
            for i in range(n):
                for j in (i - 1, i - 2):
                    if 0 <= j < n and frames[j] == 10:
                        multipliers[i] = 2
                        break
            return sum(f * m for f, m in zip(frames, multipliers))

        s1 = score(player1)
        s2 = score(player2)
        if s1 == s2:
            return 0
        return 1 if s1 > s2 else 2

