class Solution:
    def isWinner(self, player1, player2):
        def score(frames):
            total = 0
            for i, x in enumerate(frames):
                bonus = 2 if (i >= 1 and frames[i - 1] == 10) or (i >= 2 and frames[i - 2] == 10) else 1
                total += bonus * x
            return total

        s1 = score(player1)
        s2 = score(player2)
        if s1 > s2:
            return 1
        if s2 > s1:
            return 2
        return 0

