var isWinner = function(player1, player2) {
    function score(frames) {
        let total = 0;
        for (let i = 0; i < frames.length; i++) {
            const bonus = ((i >= 1 && frames[i - 1] === 10) || (i >= 2 && frames[i - 2] === 10)) ? 2 : 1;
            total += bonus * frames[i];
        }
        return total;
    }
    const s1 = score(player1);
    const s2 = score(player2);
    if (s1 > s2) return 1;
    if (s2 > s1) return 2;
    return 0;
};
